'use strict'
const fs = require('node:fs')
const path = require('node:path')

const ENGINE_DIR = path.join(__dirname, '..', 'demos', 'engine')
const PART_FILES = [
  'block.js', 'head.js', 'piston.js', 'conrod.js',
  'crankshaft.js', 'valves.js', 'ports.js'
]
const ENTRY = 'assembly.js'

const stripStrictPragma = (src) => src.replace(/^['"]use strict['"];?\s*\n/m, '')
const stripInternalRequires = (src) =>
  src.replace(/const\s+\{[^}]*\}\s*=\s*require\(['"]\.\/[^'"]+['"]\)\s*;?\s*\n/g, '')

// Extract the export-names list from a `module.exports = { a, b: c, d }` line
// and remove that line from the source.
const extractAndStripExports = (src) => {
  const m = src.match(/^module\.exports\s*=\s*\{([^}]*)\}\s*;?\s*$/m)
  if (!m) return { names: [], body: src }
  const names = m[1]
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => s.split(':')[0].trim())
  const body = src.replace(/^module\.exports\s*=\s*\{[^}]*\}\s*;?\s*$/m, '')
  return { names, body }
}

/**
 * Wrap a per-part file body in an IIFE so that its top-level const/let
 * declarations (e.g. `const { primitives, booleans, transforms } =
 * require('@jscad/modeling')`, `const cuboid = primitives.cuboid`) are
 * scoped locally. The IIFE returns the original module.exports object,
 * which we destructure at top level so build functions are visible to
 * the assembly entry.
 */
const wrapPart = (filename) => {
  const raw = fs.readFileSync(path.join(ENGINE_DIR, filename), 'utf8')
  const noStrict = stripStrictPragma(raw)
  const { names, body } = extractAndStripExports(noStrict)
  if (names.length === 0) {
    throw new Error(`bundle-engine: could not parse module.exports in ${filename}`)
  }
  const returnObj = `{ ${names.join(', ')} }`
  const destructure = `const ${returnObj} = (() => {\n${body}\nreturn ${returnObj}\n})()\n`
  return destructure
}

/**
 * Concatenate the engine modules into a single self-contained JSCAD file.
 * Header emits one `'use strict'` pragma; each part file is wrapped in
 * an IIFE so per-file destructures of @jscad/modeling do not collide; the
 * entry file contributes main + parts + getParameterDefinitions at top
 * level so the final `module.exports` can reference them.
 */
const bundleEngine = () => {
  const wrappedParts = PART_FILES.map(wrapPart)

  // Entry: strip strict pragma, strip relative requires, strip its
  // module.exports (we re-emit a canonical one at the end).
  const entryRaw = fs.readFileSync(path.join(ENGINE_DIR, ENTRY), 'utf8')
  const entrySrc = extractAndStripExports(
    stripInternalRequires(stripStrictPragma(entryRaw))
  ).body

  const header = `'use strict'
// AUTOGENERATED by scripts/bundle-engine.js -- do not edit by hand.
// Single-file bundle of demos/engine/* for use with openjscad.xyz.
// Canonical readable source: https://github.com/caliperhq/jscad-mcp-example/tree/main/demos/engine
`

  return [
    header,
    ...wrappedParts,
    entrySrc,
    'module.exports = { main, parts: _defaultParts, getParameterDefinitions }\n'
  ].join('\n')
}

const writeBundled = () => {
  const out = path.join(ENGINE_DIR, 'engine_bundled.jscad')
  fs.writeFileSync(out, bundleEngine())
  console.log(`Wrote ${out}`)
}

if (require.main === module) writeBundled()

module.exports = { bundleEngine, writeBundled }
